/// Convert a `spikard_graphql::error::GraphQLError` error to a NAPI error.
#[allow(dead_code)]
fn graph_q_l_error_to_napi_err(e: spikard_graphql::error::GraphQLError) -> napi::Error {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard_graphql::error::GraphQLError::ExecutionError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ExecutionError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::SchemaBuildError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[SchemaBuildError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::RequestHandlingError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[RequestHandlingError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::SerializationError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[SerializationError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::JsonError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[JsonError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::ValidationError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ValidationError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::ParseError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ParseError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::AuthenticationError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[AuthenticationError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::AuthorizationError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[AuthorizationError] {}", msg))
        }
        spikard_graphql::error::GraphQLError::NotFound(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[NotFound] {}", msg))
        }
        spikard_graphql::error::GraphQLError::RateLimitExceeded(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[RateLimitExceeded] {}", msg))
        }
        spikard_graphql::error::GraphQLError::InvalidInput { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[InvalidInput] {}", msg))
        }
        spikard_graphql::error::GraphQLError::ComplexityLimitExceeded => napi::Error::new(
            napi::Status::GenericFailure,
            format!("[ComplexityLimitExceeded] {}", msg),
        ),
        spikard_graphql::error::GraphQLError::DepthLimitExceeded => {
            napi::Error::new(napi::Status::GenericFailure, format!("[DepthLimitExceeded] {}", msg))
        }
        spikard_graphql::error::GraphQLError::InternalError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[InternalError] {}", msg))
        }
        _ => napi::Error::new(napi::Status::GenericFailure, msg),
    }
}

